// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---------------------------------------------------------

/**
 * Encode a compound (created_at, id) cursor as an opaque base64 JSON string.
 */
function encodeCursor(row) {
    const payload = {
        // Use ISO string so the timestamp round-trips losslessly through JSON.
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64');
}

/**
 * Decode an opaque cursor back into { created_at, id }.
 * Throws on anything malformed so the caller can return a 400.
 */
function decodeCursor(cursor) {
    let decoded;
    try {
        decoded = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
    } catch (err) {
        throw new Error('Invalid cursor: not valid base64-encoded JSON');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        typeof decoded.id === 'undefined' ||
        typeof decoded.created_at === 'undefined'
    ) {
        throw new Error('Invalid cursor: missing required fields');
    }

    // Validate the timestamp is parseable.
    if (Number.isNaN(new Date(decoded.created_at).getTime())) {
        throw new Error('Invalid cursor: bad created_at');
    }

    return { created_at: decoded.created_at, id: decoded.id };
}

// --- Endpoint ---------------------------------------------------------------

async function getPosts(req, res) {
    // Clamp limit to a sane range to prevent abuse.
    let limit = parseInt(req.query.limit, 10) || 20;
    if (limit < 1) limit = 1;
    if (limit > 100) limit = 100;

    const { after } = req.query;

    // Build the query. We always over-fetch by one row (N+1 trick) to detect
    // whether another page exists without a COUNT.
    let sql;
    let params;

    if (after) {
        let cursor;
        try {
            cursor = decodeCursor(after);
        } catch (err) {
            return res.status(400).json({ error: err.message });
        }

        // Keyset/seek predicate matching ORDER BY created_at DESC, id DESC.
        // Row comparison `(created_at, id) < (cursorTs, cursorId)` selects all
        // rows that come strictly *after* the cursor in the sort order.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        // First page: no cursor filter.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);

    const rows = result.rows;
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Notes on key decisions

- **`(created_at, id) < ($1, $2)` row-value comparison** — PostgreSQL supports tuple comparison natively, and it correctly implements the lexicographic logic for the compound sort. It is equivalent to `created_at < $1 OR (created_at = $1 AND id < $2)`, but cleaner and just as index-friendly. Because the sort is `DESC, DESC`, "next page" rows are the ones *less than* the cursor.
- **Index requirement** — for this to actually be fast, you need a composite index matching the sort: `CREATE INDEX ON posts (created_at DESC, id DESC) WHERE published = true;` (a partial index, since you always filter `published = true`).
- **`nextCursor` is built from the last returned row** (after trimming the N+1 extra), so the next request resumes exactly where this page ended.
- **Timestamp fidelity** — `created_at` is serialized as an ISO string in the cursor so sub-second precision round-trips. If your column is `timestamptz`, passing the ISO string back as a bind parameter compares correctly.

## Why cursor-based pagination is superior here

1. **Constant-time deep pages.** `OFFSET 100000` forces Postgres to scan and discard 100k rows on every request — cost grows linearly with page depth. A keyset `WHERE (created_at, id) < (...)` does an index seek straight to the start of the page, so page 5000 is as fast as page 1.
2. **No drift / no skips or duplicates.** With offsets, rows inserted or deleted between requests shift every row's position, so users skip or re-see items while paging. A cursor anchors to a specific row's sort key, so the result set stays stable as new posts arrive at the top.
3. **Dropping the COUNT removes the other expensive scan.** `SELECT COUNT(*)` on a large table is a full index/heap scan on every request; the N+1 trick gives you `hasMore` for essentially free.

The trade-off: you lose random "jump to page N" access and an exact total count — but for an infinite-scroll / "load more" feed sorted by recency, that's exactly the access pattern you want.

